// Palindrome Verifier — runs the candidate's solution.js and prints JSON on last line
const fs = require('fs');
const path = require('path');

function runVerifier() {
  const solutionPath = path.join(__dirname, 'solution.js');
  if (!fs.existsSync(solutionPath)) {
    console.log(JSON.stringify({ passed: false, score: 0, summary: 'solution.js not found', details: { error: 'missing file' } }));
    process.exit(1);
  }

  // Capture console.log output from the solution
  const logs = [];
  const origLog = console.log;
  console.log = (...args) => { logs.push(args.map(String).join(' ')); };

  try {
    require(solutionPath);
  } catch (e) {
    console.log = origLog;
    console.log(JSON.stringify({ passed: false, score: 0, summary: 'Solution threw an error: ' + e.message, details: { error: e.message } }));
    process.exit(1);
  }

  console.log = origLog;

  // Verify palindrome output
  const lines = logs.flatMap(l => l.split('\n')).filter(l => l.trim());
  const expected = ["true", "false", "true", "false", "true"];
  let passed = true;
  const details = [];

  if (lines.length !== expected.length) {
    passed = false;
    details.push('Expected ' + expected.length + ' lines, got ' + lines.length);
  }

  for (let i = 0; i < expected.length; i++) {
    const line = lines[i];
    const exp = expected[i];
    if (line !== exp) {
      passed = false;
      details.push('Line ' + (i + 1) + ': expected "' + exp + '", got "' + (line || '(empty)') + '"');
    }
  }

  const correctCount = expected.length - details.length;
  const score = Math.round((correctCount / expected.length) * 10);

  if (passed) {
    details.push('All 5 palindrome tests passed!');
  }

  const summary = passed ? 'All palindrome tests passed!' : correctCount + '/' + expected.length + ' tests passed. See details.';
  console.log(JSON.stringify({ passed, score, summary, details }));
}

runVerifier();
